import{_ as a,o,c as e,ag as s}from"./chunks/framework.DAY4Zhxq.js";const m=JSON.parse('{"title":"Multi-Host Management","description":"","frontmatter":{},"headers":[],"relativePath":"guide/multi-host.md","filePath":"guide/multi-host.md"}'),i={name:"guide/multi-host.md"};function l(n,t,r,h,d,c){return o(),e("div",null,[...t[0]||(t[0]=[s('<h1 id="multi-host-management" tabindex="-1">Multi-Host Management <a class="header-anchor" href="#multi-host-management" aria-label="Permalink to &quot;Multi-Host Management&quot;">​</a></h1><p>Alpaka Desktop can connect to multiple Ollama instances simultaneously — useful for running different models on different machines, or routing between a local instance and Ollama Cloud.</p><h2 id="adding-a-host" tabindex="-1">Adding a Host <a class="header-anchor" href="#adding-a-host" aria-label="Permalink to &quot;Adding a Host&quot;">​</a></h2><ol><li>Go to <strong>Settings → Hosts</strong> (or press <code>Ctrl+H</code>).</li><li>Click <strong>Add host</strong>.</li><li>Enter the host URL (e.g. <code>http://192.168.1.10:11434</code> for a LAN server, or <code>https://api.ollama.com</code> for Ollama Cloud).</li><li>Click <strong>Save</strong>. Alpaka Desktop immediately pings the host.</li></ol><h2 id="health-monitoring" tabindex="-1">Health Monitoring <a class="header-anchor" href="#health-monitoring" aria-label="Permalink to &quot;Health Monitoring&quot;">​</a></h2><p>Each host shows a status indicator:</p><ul><li>🟢 <strong>Green</strong> — reachable, latency shown in ms</li><li>🔴 <strong>Red</strong> — unreachable</li><li>⚪ <strong>Grey</strong> — not yet pinged</li></ul><p>The health loop pings all hosts in the background. Status updates appear in the top bar as soon as a ping completes.</p><h2 id="switching-hosts" tabindex="-1">Switching Hosts <a class="header-anchor" href="#switching-hosts" aria-label="Permalink to &quot;Switching Hosts&quot;">​</a></h2><p>Click the host indicator in the top bar to open a quick-switcher. Selecting a different host reloads the model list for that host. Your conversation history is stored locally and is available regardless of which host is active.</p><h2 id="ollama-cloud-as-a-host" tabindex="-1">Ollama Cloud as a Host <a class="header-anchor" href="#ollama-cloud-as-a-host" aria-label="Permalink to &quot;Ollama Cloud as a Host&quot;">​</a></h2><p>Adding <code>https://api.ollama.com</code> as a host enables Ollama Cloud models. The API key stored in <strong>Settings → Account → API Keys</strong> is injected automatically on all requests to this host.</p>',12)])])}const g=a(i,[["render",l]]);export{m as __pageData,g as default};
